@code {
    private string _selectedId = WarehouseState.Available[0].Id;

    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        _selectedId = e.Value?.ToString() ?? WarehouseState.Available[0].Id;
        var match = WarehouseState.Available.FirstOrDefault(w => w.Id == _selectedId);

        var newState = new WarehouseState
        {
            WarehouseId = match.Id ?? _selectedId,
            WarehouseName = match.Name ?? _selectedId
        };

        // NotifyChangedAsync pushes the new value to every [CascadingParameter]
        // subscriber, even those in a different render mode.
        await WarehouseSource.NotifyChangedAsync(newState);
    }
}

