/// <summary>
/// Scoped service that tracks low-stock alert counts per warehouse.
/// Fires OnChange so any subscribed component can re-render.
/// </summary>
public sealed class InventoryAlertService : IDisposable
{
    private readonly Random _random = new();
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;

    public int LowStockCount { get; private set; }
    public event Action? OnChange;

    /// <summary>
    /// Simulates a database query for items below minimum stock levels.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate varying counts per warehouse by seeding from the id hash.
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Begin polling every 10 seconds for the given warehouse.
    /// Multiple callers share a single timer; polling stops when all unsubscribe.
    /// </summary>
    public void StartPolling(string warehouseId)
    {
        _subscriberCount++;
        if (_subscriberCount > 1)
            return; // timer already running

        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));

        _ = PollLoopAsync(warehouseId, _cts.Token);
    }

    /// <summary>
    /// Decrement subscriber count; stop polling when it reaches zero.
    /// </summary>
    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount == 0)
        {
            _cts?.Cancel();
            _timer?.Dispose();
            _timer = null;
        }
    }

    /// <summary>
    /// Force an immediate refresh (e.g. after warehouse change).
    /// </summary>
    public async Task RefreshAsync(string warehouseId)
    {
        LowStockCount = await GetLowStockCountAsync(warehouseId);
        OnChange?.Invoke();
    }

    private async Task PollLoopAsync(string warehouseId, CancellationToken ct)
    {
        // Fire once immediately so callers get data without waiting 10 s.
        await RefreshAsync(warehouseId);

        try
        {
            while (_timer is not null && await _timer.WaitForNextTickAsync(ct))
            {
                LowStockCount = await GetLowStockCountAsync(warehouseId);
                OnChange?.Invoke();
            }
        }
        catch (OperationCanceledException) { /* expected on StopPolling / Dispose */ }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _timer?.Dispose();
    }
}
"}

