@page "/dashboard"
@rendermode InteractiveServer
@using sv_a21200d312404c3b8b11d00ed9da13cc.Models
@using sv_a21200d312404c3b8b11d00ed9da13cc.Services
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard – @Warehouse?.WarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4" style="max-width: 400px;">
    <div class="card-body">
        <h5 class="card-title">@Warehouse?.WarehouseName</h5>
        <p class="card-text mb-1">
            Low-stock items:
            @if (AlertService.LowStockCount > 0)
            {
                <span class="badge bg-danger fs-6">@AlertService.LowStockCount</span>
            }
            else
            {
                <span class="badge bg-success fs-6">0</span>
            }
        </p>
        <small class="text-muted">Refreshes every 10 seconds</small>
    </div>
</div>

@code {
    [CascadingParameter]
    private WarehouseState? Warehouse { get; set; }

    private Action? _handler;
    private string? _activeWarehouseId;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnChange += _handler;
    }

    protected override async Task OnParametersSetAsync()
    {
        var currentId = Warehouse?.WarehouseId ?? "WH-001";

        if (_activeWarehouseId != currentId)
        {
            // Warehouse changed — restart polling for the new warehouse.
            if (_activeWarehouseId is not null)
                AlertService.StopPolling();

            _activeWarehouseId = currentId;
            AlertService.StartPolling(_activeWarehouseId);

            // Immediate refresh so the UI shows data right away.
            await AlertService.RefreshAsync(_activeWarehouseId);
        }
    }

    public void Dispose()
    {
        AlertService.OnChange -= _handler;
        AlertService.StopPolling();
    }
}

